import React, { createContext, useContext, useState, useEffect } from 'react';

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check for stored token on mount
    const storedUser = localStorage.getItem('gs_user');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    setLoading(false);
  }, []);

  const login = (userData) => {
    setUser(userData);
    localStorage.setItem('gs_user', JSON.stringify(userData));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('gs_user');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { useState, useEffect } from 'react';
import Header from '../components/Header';
import SearchBar from '../components/SearchBar';
import MapView from '../components/MapView';
import NearYou from '../components/NearYou';
import BottomNav from '../components/BottomNav';
import Chatbot from '../components/Chatbot';
import LocationModal from '../components/LocationModal';
import Reviews from './Reviews';
import { parkService } from '../services/api';

const Home = () => {
  const [parks, setParks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPark, setSelectedPark] = useState(null);
  const [activeTab, setActiveTab] = useState('explore');
  const [showChatbot, setShowChatbot] = useState(false);
  const [showLocationModal, setShowLocationModal] = useState(true);

  useEffect(() => {
    const fetchParks = async () => {
      try {
        setLoading(true);
        const data = await parkService.getAllParks();
        
        const formattedData = data.map(park => ({
          ...park,
          lat: park.lat || park.latitude || 6.458985,
          lng: park.lon || park.lng || park.longitude || 3.426131,
          name: park.name || 'Green Space',
          image: park.image_url || null,
          status: park.condition || 'Open',
          cleanliness: park.cleanliness || 'Clean',
          crowd_level: park.crowd_level || 'Moderate crowds',
          busy_times: park.busy_times || 'Busy on weekends + Evenings',
          notes: park.notes || 'Often hosts events, concerts'
        }));

        setParks(formattedData);
        setLoading(false);
      } catch (err) {
        console.error('Failed to fetch parks:', err);
        setError('Unable to load data. Please check your connection.');
        setLoading(false);
      }
    };

    fetchParks();
  }, []);

  const handleReportCondition = () => {
    alert('Report feature coming soon!');
  };

  const filteredParks = parks
    .filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => {
      const aStarts = a.name.toLowerCase().startsWith(searchTerm.toLowerCase());
      const bStarts = b.name.toLowerCase().startsWith(searchTerm.toLowerCase());
      if (aStarts && !bStarts) return -1;
      if (!aStarts && bStarts) return 1;
      return 0;
    });

  const renderContent = () => {
    if (activeTab === 'reviews') {
      return <Reviews parks={filteredParks} onParkClick={(p) => { setSelectedPark(p); setActiveTab('explore'); }} />;
    }

    if (activeTab === 'notifications') {
      return (
        <div className="p-10 text-center text-neutral-400">
          <p className="text-lg font-bold">Notifications</p>
          <p className="text-sm mt-2">You're all caught up! No new alerts for your favorite parks.</p>
        </div>
      );
    }

    return (
      <main className="content-scroll">
        <SearchBar value={searchTerm} onChange={setSearchTerm} />
        
        <div className="animate-[fadeIn_0.4s_ease-out_forwards]">
          <MapView 
            parks={filteredParks} 
            selectedPark={selectedPark} 
            onMarkerClick={setSelectedPark} 
            onChatClick={() => setShowChatbot(true)}
          />

          <div className="px-4 pb-4 mt-6">
            <button className="btn-primary" onClick={handleReportCondition}>
              Report current condition
            </button>
          </div>

          {loading ? (
            <div className="p-4 text-center text-neutral-400 text-sm">Loading near you...</div>
          ) : (
            <NearYou parks={filteredParks} onParkClick={setSelectedPark} />
          )}
        </div>
      </main>
    );
  };

  return (
    <div className="app-container overflow-hidden">
      <Header />
      
      {renderContent()}

      <BottomNav activeTab={activeTab} onTabChange={setActiveTab} />

      {showChatbot && <Chatbot onClose={() => setShowChatbot(false)} />}
      
      {showLocationModal && (
        <LocationModal 
          onEnable={() => setShowLocationModal(false)} 
          onDeny={() => setShowLocationModal(false)} 
        />
      )}
    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { RiUserLine, RiMailLine, RiLockPasswordLine, RiLeafFill } from 'react-icons/ri';
import './Auth.css';

const Signup = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const { authService } = await import('../services/api');
      const data = await authService.register(email, password);
      // Supabase signUp returns user data. For immediate login, we might need another step or just tell user to login.
      // But typically it returns a session if configured.
      if (data.user) {
        // Redirect to login or auto-login if session exists
        navigate('/login', { state: { message: 'Account created! Please login.' } });
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Signup failed. Email might already be in use.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-container">
      <div className="auth-card glass-morphism">
        <Link to="/" className="auth-logo">
          <RiLeafFill className="logo-icon" />
          <span>Green<span>Sight</span></span>
        </Link>
        <h2>Join GreenSight</h2>
        <p className="auth-subtitle">Discover and verify green spaces across Nigeria.</p>
        
        {error && <div className="auth-error-message">{error}</div>}
        
        <form onSubmit={handleSubmit}>
          <div className="input-group">
            <RiUserLine className="input-icon" />
            <input 
              type="text" 
              placeholder="Full Name (e.g. Tunde)" 
              value={name}
              onChange={(e) => setName(e.target.value)}
              required 
            />
          </div>

          <div className="input-group">
            <RiMailLine className="input-icon" />
            <input 
              type="email" 
              placeholder="Email Address" 
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required 
            />
          </div>
          
          <div className="input-group">
            <RiLockPasswordLine className="input-icon" />
            <input 
              type="password" 
              placeholder="Create Password" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required 
            />
          </div>

          <button type="submit" className="btn-primary auth-submit" disabled={loading}>
            {loading ? "Creating Account..." : "Create Account"}
          </button>
        </form>

        <p className="auth-footer">
          Already a member? <Link to="/login">Login here</Link>
        </p>
      </div>
    </div>
  );
};

export default Signup;
